(self.webpackChunktradingview=self.webpackChunktradingview||[]).push([[13671],{289309:e=>{e.exports=["Cookies used to integrate third party services.{bold_end} These cookies are used to integrate third-party functions on the Site, such as videos, maps, or social network plug-ins."]},353714:e=>{e.exports=["Cookies Policy"]},98753:e=>{e.exports=['Cookies can be stored on your computer for various periods of time. They can be in a form of either "session cookies" or "persistent cookies." A session cookie only lasts as long as the browser session and is automatically deleted when you close your browser. A persistent cookie lasts long after your browser is closed and will remain until it expires (as determined by the third party in charge of placing it) or until you delete the cookie. Persistent cookies are used to help sites recognize and identify your computer when you open your browser and surf the Internet again.']},980029:e=>{e.exports=["Changes"]},259108:e=>{e.exports=["A 'cookie' is a piece of information that is sent to your browser by a website you visit. The Site uses first party cookies (those set by a website that is being visited by the user at the time. For example, cookies via www.tradingview.com) as well as third-party cookies (set by a different domain), as described below."]},489962:e=>{e.exports=["Ad cookies"]},633755:e=>{e.exports=["Advertising cookies (ad cookies).{bold_end} These cookies are used to show advertising that is relevant to you."]},595797:e=>{e.exports=["Google Advertising"]},708535:e=>{e.exports=["Google Analytics"]},367141:e=>{e.exports=["For other browsers, please consult the documentation that your browser manufacturer provides."]},865696:e=>{e.exports=["How do we use cookies?"]},913436:e=>{e.exports=["Other third party cookies.{bold_end}On some parts of the Site, including, but not limited, to news widgets, we use content provided by other websites(third parties). These third party sites are able to set their own cookies in some cases. Note that we have no control over these third-party cookies. You can turn them off by disabling them on your browser. You can find more information on the most popular web-browser help pages:"]},43680:e=>{e.exports=["More information on our use of cookies can be found in the table below:"]},582403:e=>{e.exports=["Manage your privacy preferences"]},283817:e=>{e.exports=["Necessary cookies"]},934078:e=>{e.exports=["Necessary cookies.{bold_end} These cookies are used to provide users with services available through a Site and to use some of its features, such as the ability to log-in and access secure areas, provide pop-up notices, and accept language from sign-up forms. These cookies are essential for using and navigating a Site. Without them, basic functions of our Site would not work. Because these cookies are strictly necessary to deliver our Site's essential services, you cannot refuse them."]},424055:e=>{e.exports=["Performance cookies"]},985612:e=>{e.exports=["Performance and ad cookies"]},247243:e=>{
e.exports=["Performance/Analytics cookies.{bold_end} These cookies are used to recognize and count the number of Site visitors, gather statistics regarding how visitors move around the Site (including number of page views and the amount time spent on each page) and for conversion tracking and click hotspots. This helps us improve the way our Site works and general user experience. For example, these cookies allow us to ensure that users are able to find what they need easily."]},707229:e=>{e.exports=["We may change the type of third party service providers that place cookies on our Site and amend this Cookies Policy at any time by posting the amended version on our Site. Unless additional notice or consent is required by applicable laws, this will serve as your official notification of these changes."]},990051:e=>{e.exports=["We use these cookies for user authentication and identification, in order to make our features and functions more readily available. In addition, we use necessary cookies for user interface customization and security features such as detecting fraud and abuse. We also use Web Storage and IndexedDB technologies to store user preferences and information that is necessary for providing our services. We use evercookie technology to implement security features and detect violations of our Terms of Use. Examples of the specific cookies used for this purpose are cachec, sessionid, and tv_ecuid."]},443109:e=>{e.exports=["Web beacons"]},244424:e=>{e.exports=["Web beacons, also called tracking pixels, are tiny graphics with unique identifiers that allow us to track usage patterns, count users who have visited a particular page, advertising impressions and clicks (ad reactions), etc. Web beacons can only collect limited information, including a cookie number, time and date of a page view, and a description of the page on which the web beacon resides. These beacons do not carry any personal data and are only used to track the effectiveness of this Site and to show advertisements based on user interests. We use web beacons in connection with Google Analytics and advertising services as well as our Snowplow Tracker. The information generated relating to our Site is used for various necessary and legitimate purposes, including the creation of reports on the use of this site as well as the development, testing, and improvement of services. Google will store information of users' actions on the TradingView Site and it will be collected by Google services. For more information on Google's use of data for marketing and analytics purposes, please see {ads_link}Advertising – Privacy & Terms{end_link} and {GPP_link}Google's Privacy Policy{end_link}."]},75564:e=>{e.exports=["What is a cookie?"]},349357:e=>{
e.exports=["The data collected through cookies may include information about the IP (Internet Protocol) address of your device, browser type, language, operating system, the state or country from which you have accessed the Site, the date and the time of your visit(s), the number of links you click on this Site, the functions you use, the searches you request, and the data you have saved while on this Site. TradingView may use the information collected for a variety of necessary, legitimate purposes, including user authentication, user interface customization, security, research and analysis to improve the functionality of our Site, and advertising (for more information on how we use your data, please read our {pp_link}Privacy Policy{link_end})."]},461710:e=>{e.exports=["The following sets out how we use different categories of cookies, as well as information on your options for managing your settings for the data collected by these technologies:"]},201167:e=>{e.exports=["These cookies are used to collect and analyze information about how you use the Site. We use this information to analyze and improve our services. These cookies collect information pseudonymously. Examples of cookies used for this purpose are __ga, __utma, and __git. The information about your use of the Site (including your IP address) will be transmitted to and stored by Google, Inc. in the United States (pursuant to Google's Privacy Shield certification). This is all generated by Google Analytics. For more information on Google Analytics and their privacy practices, check {analytics_link}here{link_end}. You can find more information about Google Analytics and their cookie usage and expiration {dev_analytics_link}here{link_end}."]},691287:e=>{e.exports=["These cookies are used to collect and analyze information about how you use the Site. We use this information to analyze and improve our services. These cookies collect information pseudonymously. Examples of cookies used for this purpose are _sp_id.* and _sp_ses.*."]},959963:e=>{e.exports=["These cookies are used to show you advertisements and for remarketing and tracking purposes."]},264835:e=>{e.exports=["These cookies are used for remarketing and tracking purposes."]},319888:e=>{e.exports=['This Cookies Policy ("Cookies Policy") describes cookies and other technologies that TradingView, Inc. ("TradingView", "we", "us" or "our") uses on its website ("Site") and the choices that users have. This Cookies Policy is a part of TradingView\'s Privacy Policy. When you first visit the Site, you will be asked to consent to the use of cookies in accordance with this Cookies Policy. Note that if you accept, we will store them on your computer.']},129702:e=>{e.exports=["TradingView Snowplow Tracker"]},512623:e=>{e.exports=["X (formerly Twitter)"]},61472:e=>{e.exports=["You can find out more about cookies (including how to see or manage them) at {allaboutcookies_link}All About Cookies{link_end} or {aboutcookies_link}AboutCookies.org{link_end} websites."]}}]);